  1→import type { SDUIContext, SDUIRule } from '../models';
  2→import { evaluateRule } from './jsonLogic';
  3→
  4→const CONTEXT: SDUIContext = {
  5→  form: {
  6→    points: 5000,
  7→    reais: 50,
  8→  },
  9→  balance: {
 10→    points: 25720,
 11→    pointsFormatted: '25.720',
 12→  },
 13→  product: {
 14→    code: 206,
 15→    name: 'Abastecimento',
 16→    active: true,
 17→  },
 18→  user: {
 19→    eligible: true,
 20→    blocked: false,
 21→    tier: 'gold',
 22→  },
 23→  empty: null,
 24→};
 25→
 26→describe('evaluateRule', () => {
 27→  describe('var operator', () => {
 28→    it('resolves context values for comparison', () => {
 29→      const rule: SDUIRule = { '>': [{ var: 'form.points' }, 0] };
 30→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
 31→    });
 32→
 33→    it('resolves nested context paths', () => {
 34→      const rule: SDUIRule = {
 35→        '==': [{ var: 'product.name' }, 'Abastecimento'],
 36→      };
 37→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
 38→    });
 39→
 40→    it('resolves both operands from context', () => {
 41→      const rule: SDUIRule = {
 42→        '<=': [{ var: 'form.points' }, { var: 'balance.points' }],
 43→      };
 44→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
 45→    });
 46→
 47→    it('resolves missing path to empty string', () => {
 48→      const rule: SDUIRule = { '==': [{ var: 'nonexistent.path' }, ''] };
 49→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
 50→    });
 51→  });
 52→
 53→  describe('comparison operators', () => {
 54→    it('== with loose equality', () => {
 55→      expect(evaluateRule({ '==': [1, 1] }, CONTEXT)).toBe(true);
 56→      expect(evaluateRule({ '==': [1, '1'] }, CONTEXT)).toBe(true);
 57→      expect(evaluateRule({ '==': [1, 2] }, CONTEXT)).toBe(false);
 58→      expect(evaluateRule({ '==': [null, null] }, CONTEXT)).toBe(true);
 59→    });
 60→
 61→    it('!= with loose inequality', () => {
 62→      expect(evaluateRule({ '!=': [1, 2] }, CONTEXT)).toBe(true);
 63→      expect(evaluateRule({ '!=': [1, 1] }, CONTEXT)).toBe(false);
 64→      expect(evaluateRule({ '!=': [1, '1'] }, CONTEXT)).toBe(false);
 65→    });
 66→
 67→    it('> greater than', () => {
 68→      expect(evaluateRule({ '>': [10, 5] }, CONTEXT)).toBe(true);
 69→      expect(evaluateRule({ '>': [5, 10] }, CONTEXT)).toBe(false);
 70→      expect(evaluateRule({ '>': [5, 5] }, CONTEXT)).toBe(false);
 71→    });
 72→
 73→    it('< less than', () => {
 74→      expect(evaluateRule({ '<': [5, 10] }, CONTEXT)).toBe(true);
 75→      expect(evaluateRule({ '<': [10, 5] }, CONTEXT)).toBe(false);
 76→    });
 77→
 78→    it('>= greater than or equal', () => {
 79→      expect(evaluateRule({ '>=': [10, 5] }, CONTEXT)).toBe(true);
 80→      expect(evaluateRule({ '>=': [5, 5] }, CONTEXT)).toBe(true);
 81→      expect(evaluateRule({ '>=': [4, 5] }, CONTEXT)).toBe(false);
 82→    });
 83→
 84→    it('<= less than or equal', () => {
 85→      expect(evaluateRule({ '<=': [5, 10] }, CONTEXT)).toBe(true);
 86→      expect(evaluateRule({ '<=': [5, 5] }, CONTEXT)).toBe(true);
 87→      expect(evaluateRule({ '<=': [6, 5] }, CONTEXT)).toBe(false);
 88→    });
 89→
 90→    it('with context values', () => {
 91→      expect(
 92→        evaluateRule({ '>': [{ var: 'form.points' }, 1000] }, CONTEXT),
 93→      ).toBe(true);
 94→      expect(
 95→        evaluateRule({ '<': [{ var: 'form.points' }, 1000] }, CONTEXT),
 96→      ).toBe(false);
 97→    });
 98→
 99→    it('string comparison', () => {
100→      expect(
101→        evaluateRule(
102→          { '==': [{ var: 'user.tier' }, 'gold'] },
103→          CONTEXT,
104→        ),
105→      ).toBe(true);
106→      expect(
107→        evaluateRule(
108→          { '!=': [{ var: 'user.tier' }, 'silver'] },
109→          CONTEXT,
110→        ),
111→      ).toBe(true);
112→    });
113→
114→    it('boolean comparison', () => {
115→      expect(
116→        evaluateRule({ '==': [{ var: 'product.active' }, true] }, CONTEXT),
117→      ).toBe(true);
118→      expect(
119→        evaluateRule({ '==': [{ var: 'user.blocked' }, false] }, CONTEXT),
120→      ).toBe(true);
121→    });
122→  });
123→
124→  describe('logical operators', () => {
125→    it('and: all true', () => {
126→      const rule: SDUIRule = {
127→        and: [
128→          { '>': [{ var: 'form.points' }, 0] },
129→          { '<=': [{ var: 'form.points' }, { var: 'balance.points' }] },
130→        ],
131→      };
132→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
133→    });
134→
135→    it('and: one false', () => {
136→      const rule: SDUIRule = {
137→        and: [
138→          { '>': [{ var: 'form.points' }, 0] },
139→          { '>': [{ var: 'form.points' }, 100000] },
140→        ],
141→      };
142→      expect(evaluateRule(rule, CONTEXT)).toBe(false);
143→    });
144→
145→    it('and: empty array returns true (vacuous truth)', () => {
146→      const rule: SDUIRule = { and: [] };
147→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
148→    });
149→
150→    it('or: at least one true', () => {
151→      const rule: SDUIRule = {
152→        or: [
153→          { '==': [{ var: 'product.code' }, 205] },
154→          { '==': [{ var: 'product.code' }, 206] },
155→        ],
156→      };
157→      expect(evaluateRule(rule, CONTEXT)).toBe(true);
158→    });
159→
160→    it('or: all false', () => {
161→      const rule: SDUIRule = {
162→        or: [
163→          { '==': [{ var: 'product.code' }, 999] },
164→          { '==': [{ var: 'product.code' }, 888] },
