import type {
  SDUIContext,
  SDUIRule,
  SDUILogicOperand,
  SDUIVarOperator,
  SDUILogicPrimitive,
} from '../models';
import { resolveContextPath } from './interpolation';

const MAX_DEPTH = 20;

const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);

function isVarOperator(operand: SDUILogicOperand): operand is SDUIVarOperator {
  return (
    operand !== null &&
    typeof operand === 'object' &&
    'var' in operand &&
    typeof (operand as SDUIVarOperator).var === 'string'
  );
}

function isPrimitive(value: unknown): value is SDUILogicPrimitive {
  return (
    value === null ||
    typeof value === 'string' ||
    typeof value === 'number' ||
    typeof value === 'boolean'
  );
}

function resolveOperand(
  operand: SDUILogicOperand,
  context: SDUIContext,
  depth: number,
): SDUILogicPrimitive {
  if (isPrimitive(operand)) return operand;
  if (isVarOperator(operand)) {
    const resolved = resolveContextPath(context, operand.var);
    if (isPrimitive(resolved)) return resolved;
    return null;
  }
  return evaluate(operand as SDUIRule, context, depth + 1);
}

function evaluateComparison(
  operator: string,
  operands: [SDUILogicOperand, SDUILogicOperand],
  context: SDUIContext,
  depth: number,
): boolean {
  const left = resolveOperand(operands[0], context, depth);
  const right = resolveOperand(operands[1], context, depth);

  switch (operator) {
    case '==':
      return left == right; // eslint-disable-line eqeqeq
    case '!=':
      return left != right; // eslint-disable-line eqeqeq
    case '>':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left > right;
    case '<':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left < right;
    case '>=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left >= right;
    case '<=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left <= right;
    default:
      return false;
  }
}

function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
  if (!rule || typeof rule !== 'object') return false;
  if (depth > MAX_DEPTH) return false;

  const keys = Object.keys(rule);
  if (keys.length === 0) return false;

  const operator = keys[0];
  const operands = (rule as Record<string, unknown>)[operator];

  if (operator === 'and') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === 'or') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === '!') {
    const inner = Array.isArray(operands) ? operands[0] : operands;
    return !evaluate(inner as SDUIRule, context, depth + 1);
  }

  if (COMPARISON_OPS.has(operator)) {
    if (!Array.isArray(operands) || operands.length !== 2) return false;
    return evaluateComparison(
      operator,
      operands as [SDUILogicOperand, SDUILogicOperand],
      context,
      depth,
    );
  }

  return false;
}

export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
  return evaluate(rule, context, 0);
}

