describe('evaluateExpression', () => {
  describe('addition (+)', () => {
    it('adds two numbers', () => {
      const expr: SDUIArithmeticExpression = { '+': [10, 20] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(30);
    });

    it('adds multiple numbers (variadic)', () => {
      const expr: SDUIArithmeticExpression = { '+': [1, 2, 3, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(10);
    });

    it('adds context values', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'form.points' }, { var: 'form.reais' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(5050);
    });

    it('coerces numeric strings', () => {
      const expr: SDUIArithmeticExpression = { '+': ['10', 20] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(30);
    });
  });

  describe('subtraction (-)', () => {
    it('subtracts two numbers', () => {
      const expr: SDUIArithmeticExpression = { '-': [100, 30] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(70);
    });

    it('subtracts context values', () => {
      const expr: SDUIArithmeticExpression = { '-': [{ var: 'balance.points' }, { var: 'form.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20720);
    });
  });

  describe('multiplication (*)', () => {
    it('multiplies two numbers', () => {
      const expr: SDUIArithmeticExpression = { '*': [5, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20);
    });

    it('multiplies multiple numbers (variadic)', () => {
      const expr: SDUIArithmeticExpression = { '*': [2, 3, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(24);
    });

    it('points to reais conversion', () => {
      const expr: SDUIArithmeticExpression = { '*': [{ var: 'form.points' }, 0.01] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(50);
    });
  });

  describe('division (/)', () => {
    it('divides two numbers', () => {
      const expr: SDUIArithmeticExpression = { '/': [100, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(25);
    });

    it('returns 0 on division by zero', () => {
      const expr: SDUIArithmeticExpression = { '/': [100, 0] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('divides context values', () => {
      const expr: SDUIArithmeticExpression = { '/': [{ var: 'form.reais' }, 0.01] };
      expect(evaluateExpression(expr, CONTEXT)).toBeCloseTo(5000);
    });
  });

  describe('min / max', () => {
    it('returns minimum', () => {
      const expr: SDUIArithmeticExpression = { min: [10, 5, 20, 3] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(3);
    });

    it('returns maximum', () => {
      const expr: SDUIArithmeticExpression = { max: [10, 5, 20, 3] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20);
    });

    it('min with context values', () => {
      const expr: SDUIArithmeticExpression = { min: [{ var: 'form.points' }, { var: 'balance.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(5000);
    });

    it('max with context values', () => {
      const expr: SDUIArithmeticExpression = { max: [{ var: 'form.points' }, { var: 'balance.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(25720);
    });
  });

  describe('nested arithmetic', () => {
    it('nested multiplication inside addition', () => {
      // (points * 0.01) + 10
      const expr: SDUIArithmeticExpression = {
        '+': [
          { '*': [{ var: 'form.points' }, 0.01] },
          10,
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBe(60);
    });

    it('complex formula: (balance - points) * factor', () => {
      const expr: SDUIArithmeticExpression = {
        '*': [
          { '-': [{ var: 'balance.points' }, { var: 'form.points' }] },
          0.01,
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBeCloseTo(207.20);
    });

    it('min of computed values', () => {
      const expr: SDUIArithmeticExpression = {
        min: [
          { '*': [{ var: 'form.points' }, 2] },
          { var: 'balance.points' },
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBe(10000);
    });
  });

  describe('passthrough for primitives and var', () => {
    it('returns primitive directly', () => {
      expect(evaluateExpression(42 as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(42);
      expect(evaluateExpression('hello' as unknown as SDUIArithmeticExpression, CONTEXT)).toBe('hello');
      expect(evaluateExpression(true as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(true);
      expect(evaluateExpression(null as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(null);
    });

    it('resolves var operator', () => {
      expect(evaluateExpression({ var: 'form.points' } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(5000);
    });

    it('evaluates boolean rule', () => {
      expect(evaluateExpression({ '>': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(true);
      expect(evaluateExpression({ '<': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(false);
    });
  });

  describe('edge cases', () => {
    it('returns 0 for empty operands array', () => {
      expect(evaluateExpression({ '+': [] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 for non-array operands', () => {
      expect(evaluateExpression({ '+': 'invalid' } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 when operand resolves to non-numeric', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'product.name' }, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('returns 0 for null operand in arithmetic', () => {
      const expr: SDUIArithmeticExpression = { '+': [null, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('returns 0 for subtraction with wrong operand count', () => {
      expect(evaluateExpression({ '-': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
      expect(evaluateExpression({ '-': [1, 2, 3] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 for division with wrong operand count', () => {
      expect(evaluateExpression({ '/': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('respects max depth', () => {
      let expr: SDUIArithmeticExpression = { '+': [1, 1] };
      for (let i = 0; i < 25; i++) {
        expr = { '+': [expr as unknown as number, 1] };
      }
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('returns 0 for object resolving to non-primitive via var', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'product' }, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('handles boolean operand as non-numeric', () => {
      const expr: SDUIArithmeticExpression = { '+': [true as unknown as number, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });
  });
});

