      const rule: SDUIRule = {
        '>': [
          { '+': [{ var: 'form.points' }, 100] } as unknown as SDUILogicOperand,
          { var: 'form.points' },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });
});

describe('evaluateExpression', () => {
  describe('addition (+)', () => {
