      expect(evaluateExpression(expr, CONTEXT)).toBe(30);
    });

    it('adds multiple numbers (variadic)', () => {
      const expr: SDUIArithmeticExpression = { '+': [1, 2, 3, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(10);
    });

    it('adds context values', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'form.points' }, { var: 'form.reais' }] };
