it('respects max depth', () => {
  // Build deeply nested: +(+(+(... 1, 1), 1), 1) — 25 levels deep
  // At depth > 20, computeArithmetic returns 0
  // Inner levels that exceed depth return 0, so the deepest operand
  // resolves to 0 instead of its true value, capping computation
  let expr: SDUIArithmeticExpression = { '+': [1000, 1000] };
  for (let i = 0; i < 25; i++) {
    expr = { '+': [expr as unknown as number, 1000] };
  }
  // Without depth limit: 2000 + 25*1000 = 27000
  // With depth limit at 20: innermost levels return 0, so result < 27000
  const result = evaluateExpression(expr, CONTEXT) as number;
  expect(result).toBeLessThan(27000);
});

