import type { SDUIContext, SDUIRule, SDUIArithmeticExpression } from '../models';
import { evaluateRule, evaluateExpression } from './jsonLogic';

const CONTEXT: SDUIContext = {
  form: {
    points: 5000,
    reais: 50,
  },
  balance: {
    points: 25720,
    pointsFormatted: '25.720',
  },
  product: {
    code: 206,
    name: 'Abastecimento',
    active: true,
  },
  user: {
    eligible: true,
    blocked: false,
    tier: 'gold',
  },
  empty: null,
};

describe('evaluateRule', () => {
  describe('var operator', () => {
    it('resolves context values for comparison', () => {
      const rule: SDUIRule = { '>': [{ var: 'form.points' }, 0] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves nested context paths', () => {
      const rule: SDUIRule = {
        '==': [{ var: 'product.name' }, 'Abastecimento'],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves both operands from context', () => {
      const rule: SDUIRule = {
        '<=': [{ var: 'form.points' }, { var: 'balance.points' }],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves missing path to empty string', () => {
      const rule: SDUIRule = { '==': [{ var: 'nonexistent.path' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('comparison operators', () => {
    it('== with loose equality', () => {
      expect(evaluateRule({ '==': [1, 1] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '==': [1, '1'] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '==': [1, 2] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '==': [null, null] }, CONTEXT)).toBe(true);
    });

    it('!= with loose inequality', () => {
      expect(evaluateRule({ '!=': [1, 2] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '!=': [1, 1] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '!=': [1, '1'] }, CONTEXT)).toBe(false);
    });

    it('> greater than', () => {
      expect(evaluateRule({ '>': [10, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>': [5, 10] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '>': [5, 5] }, CONTEXT)).toBe(false);
    });

    it('< less than', () => {
      expect(evaluateRule({ '<': [5, 10] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<': [10, 5] }, CONTEXT)).toBe(false);
    });

    it('>= greater than or equal', () => {
      expect(evaluateRule({ '>=': [10, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>=': [5, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>=': [4, 5] }, CONTEXT)).toBe(false);
    });

    it('<= less than or equal', () => {
      expect(evaluateRule({ '<=': [5, 10] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<=': [5, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<=': [6, 5] }, CONTEXT)).toBe(false);
    });

    it('with context values', () => {
      expect(
        evaluateRule({ '>': [{ var: 'form.points' }, 1000] }, CONTEXT),
      ).toBe(true);
      expect(
        evaluateRule({ '<': [{ var: 'form.points' }, 1000] }, CONTEXT),
      ).toBe(false);
    });

    it('string comparison', () => {
      expect(
        evaluateRule(
          { '==': [{ var: 'user.tier' }, 'gold'] },
          CONTEXT,
        ),
      ).toBe(true);
      expect(
        evaluateRule(
          { '!=': [{ var: 'user.tier' }, 'silver'] },
          CONTEXT,
        ),
      ).toBe(true);
    });

    it('boolean comparison', () => {
      expect(
        evaluateRule({ '==': [{ var: 'product.active' }, true] }, CONTEXT),
      ).toBe(true);
      expect(
        evaluateRule({ '==': [{ var: 'user.blocked' }, false] }, CONTEXT),
      ).toBe(true);
    });
  });

  describe('logical operators', () => {
    it('and: all true', () => {
      const rule: SDUIRule = {
        and: [
          { '>': [{ var: 'form.points' }, 0] },
          { '<=': [{ var: 'form.points' }, { var: 'balance.points' }] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('and: one false', () => {
      const rule: SDUIRule = {
        and: [
          { '>': [{ var: 'form.points' }, 0] },
          { '>': [{ var: 'form.points' }, 100000] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('and: empty array returns true (vacuous truth)', () => {
      const rule: SDUIRule = { and: [] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('or: at least one true', () => {
      const rule: SDUIRule = {
        or: [
          { '==': [{ var: 'product.code' }, 205] },
          { '==': [{ var: 'product.code' }, 206] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('or: all false', () => {
      const rule: SDUIRule = {
        or: [
          { '==': [{ var: 'product.code' }, 999] },
          { '==': [{ var: 'product.code' }, 888] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('or: empty array returns false', () => {
      const rule: SDUIRule = { or: [] };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('!: negation (object syntax)', () => {
      expect(
        evaluateRule(
          { '!': { '==': [{ var: 'product.code' }, 999] } },
          CONTEXT,
        ),
      ).toBe(true);
      expect(
        evaluateRule(
          { '!': { '==': [{ var: 'product.code' }, 206] } },
          CONTEXT,
        ),
      ).toBe(false);
    });

    it('!: negation (array syntax)', () => {
      expect(
        evaluateRule(
          { '!': [{ '==': [1, 1] }] } as unknown as SDUIRule,
          CONTEXT,
        ),
      ).toBe(false);
      expect(
        evaluateRule(
          { '!': [{ '==': [1, 2] }] } as unknown as SDUIRule,
          CONTEXT,
        ),
      ).toBe(true);
    });
  });

  describe('nested logic', () => {
    it('and inside or', () => {
      const rule: SDUIRule = {
        or: [
          {
            and: [
              { '==': [{ var: 'product.code' }, 206] },
              { '>': [{ var: 'form.points' }, 1000] },
            ],
          },
          { '==': [{ var: 'user.tier' }, 'platinum'] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('not inside and', () => {
      const rule: SDUIRule = {
        and: [
          { '!': { '==': [{ var: 'user.blocked' }, true] } },
          { '==': [{ var: 'user.eligible' }, true] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('deeply nested rules', () => {
      const rule: SDUIRule = {
        and: [
          {
            or: [
              { '==': [{ var: 'product.code' }, 205] },
              { '==': [{ var: 'product.code' }, 206] },
            ],
          },
          { '!': { '==': [{ var: 'user.blocked' }, true] } },
          { '>': [{ var: 'balance.points' }, 0] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('nested rule as comparison operand', () => {
      const rule: SDUIRule = {
        '==': [
          { '>': [{ var: 'form.points' }, 0] } as unknown as SDUIRule,
          true,
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('edge cases & error handling', () => {
    it('returns false for null rule', () => {
      expect(evaluateRule(null as unknown as SDUIRule, CONTEXT)).toBe(false);
    });

    it('returns false for undefined rule', () => {
      expect(evaluateRule(undefined as unknown as SDUIRule, CONTEXT)).toBe(
        false,
      );
    });

    it('returns false for empty object', () => {
      expect(evaluateRule({} as SDUIRule, CONTEXT)).toBe(false);
    });

    it('returns false for unknown operator', () => {
      const rule = { xor: [true, false] } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for comparison with wrong operand count', () => {
      const rule = { '>': [1] } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for comparison with non-array operands', () => {
      const rule = { '>': 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for and with non-array operands', () => {
      const rule = { and: 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for or with non-array operands', () => {
      const rule = { or: 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('handles empty context', () => {
      const rule: SDUIRule = { '==': [{ var: 'anything' }, ''] };
      expect(evaluateRule(rule, {})).toBe(true);
    });

    it('handles context value resolving to object (non-primitive)', () => {
      const rule: SDUIRule = { '==': [{ var: 'product' }, null] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('returns false for ordering comparison with non-numeric types', () => {
      expect(evaluateRule({ '>': ['z', 'a'] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '<': [null, 5] }, CONTEXT)).toBe(false);
      expect(
        evaluateRule(
          { '>=': [{ var: 'product.name' }, 100] },
          CONTEXT,
        ),
      ).toBe(false);
    });

    it('returns false for deeply nested rules exceeding max depth', () => {
      let rule: SDUIRule = { '==': [1, 1] };
      for (let i = 0; i < 25; i++) {
        rule = { and: [rule] };
      }
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('blocks __proto__ access in var paths', () => {
      const rule: SDUIRule = { '==': [{ var: '__proto__' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('blocks constructor access in var paths', () => {
      const rule: SDUIRule = { '==': [{ var: 'product.constructor' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('arithmetic as comparison operands', () => {
    it('compares arithmetic result to literal', () => {
      const rule: SDUIRule = {
        '==': [
          { '*': [{ var: 'form.points' }, 0.01] } as unknown as SDUIRule,
          50,
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('compares two arithmetic results', () => {
      const rule: SDUIRule = {
        '>': [
          { '+': [{ var: 'form.points' }, 100] } as unknown as SDUIRule,
          { var: 'form.points' },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });
});

