      expect(evaluateExpression({ '>': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(true);
      expect(evaluateExpression({ '<': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(false);
