  'balance_display',
  'points_input',
  'button',
  'link',
  'alert',
  'list_text_icon',
  'separator',
  'icon_text_row',
  'section_heading',
  'nav_header',
  'rich_text',
  'voucher_card',
  'empty_state',
  'points_card',
  'tab_bar',
  'transaction_item',
  'date_separator',
  'detail_header',
  'tag_label',
  'key_value_row',
  'card_activity',
] as const;

export type SDUIKnownType = (typeof SDUI_KNOWN_TYPES)[number];

