import type {
  SDUIContext,
  SDUIRule,
  SDUIVarOperator,
  SDUILogicPrimitive,
  SDUIExpressionOperand,
  SDUIArithmeticExpression,
} from '../models';
import { resolveContextPath } from './interpolation';

const MAX_DEPTH = 20;

const COMPARISON_OPS = new Set(['==', '!=', '>', '<', '>=', '<=']);
const ARITHMETIC_OPS = new Set(['+', '-', '*', '/', 'min', 'max']);

function isVarOperator(operand: unknown): operand is SDUIVarOperator {
  return (
    operand !== null &&
    typeof operand === 'object' &&
    'var' in operand &&
    typeof (operand as SDUIVarOperator).var === 'string'
  );
}

function isPrimitive(value: unknown): value is SDUILogicPrimitive {
  return (
    value === null ||
    typeof value === 'string' ||
    typeof value === 'number' ||
    typeof value === 'boolean'
  );
}

function isArithmeticExpression(value: unknown): value is SDUIArithmeticExpression {
  if (!value || typeof value !== 'object') return false;
  const keys = Object.keys(value);
  return keys.length === 1 && ARITHMETIC_OPS.has(keys[0]);
}

function resolveOperand(
  operand: SDUIExpressionOperand,
  context: SDUIContext,
  depth: number,
): SDUILogicPrimitive {
  if (isPrimitive(operand)) return operand;
  if (isVarOperator(operand)) {
    const resolved = resolveContextPath(context, operand.var);
    if (isPrimitive(resolved)) return resolved;
    return null;
  }
  if (isArithmeticExpression(operand)) {
    return computeArithmetic(operand, context, depth + 1);
  }
  return evaluate(operand as SDUIRule, context, depth + 1);
}

function toNumber(value: SDUILogicPrimitive): number | null {
  if (typeof value === 'number') return value;
  if (typeof value === 'string') {
    const n = Number(value);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}

function computeArithmetic(
  expr: SDUIArithmeticExpression,
  context: SDUIContext,
  depth: number,
): number {
  if (depth > MAX_DEPTH) return 0;

  const keys = Object.keys(expr);
  const operator = keys[0];
  const operands = (expr as Record<string, unknown>)[operator];
  if (!Array.isArray(operands) || operands.length === 0) return 0;

  const resolved = operands.map(op =>
    toNumber(resolveOperand(op as SDUIExpressionOperand, context, depth)),
  );

  if (resolved.some(v => v === null)) return 0;
  const nums = resolved as number[];

  switch (operator) {
    case '+':
      return nums.reduce((a, b) => a + b, 0);
    case '-':
      if (nums.length !== 2) return 0;
      return nums[0] - nums[1];
    case '*':
      return nums.reduce((a, b) => a * b, 1);
    case '/':
      if (nums.length !== 2) return 0;
      if (nums[1] === 0) return 0;
      return nums[0] / nums[1];
    case 'min':
      return Math.min(...nums);
    case 'max':
      return Math.max(...nums);
    default:
      return 0;
  }
}

function evaluateComparison(
  operator: string,
  operands: [SDUIExpressionOperand, SDUIExpressionOperand],
  context: SDUIContext,
  depth: number,
): boolean {
  const left = resolveOperand(operands[0], context, depth);
  const right = resolveOperand(operands[1], context, depth);

  switch (operator) {
    case '==':
      return left == right; // eslint-disable-line eqeqeq
    case '!=':
      return left != right; // eslint-disable-line eqeqeq
    case '>':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left > right;
    case '<':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left < right;
    case '>=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left >= right;
    case '<=':
      if (typeof left !== 'number' || typeof right !== 'number') return false;
      return left <= right;
    default:
      return false;
  }
}

function evaluate(rule: SDUIRule, context: SDUIContext, depth: number): boolean {
  if (!rule || typeof rule !== 'object') return false;
  if (depth > MAX_DEPTH) return false;

  const keys = Object.keys(rule);
  if (keys.length === 0) return false;

  const operator = keys[0];
  const operands = (rule as Record<string, unknown>)[operator];

  if (operator === 'and') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).every(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === 'or') {
    if (!Array.isArray(operands)) return false;
    return (operands as SDUIRule[]).some(sub => evaluate(sub, context, depth + 1));
  }

  if (operator === '!') {
    const inner = Array.isArray(operands) ? operands[0] : operands;
    return !evaluate(inner as SDUIRule, context, depth + 1);
  }

  if (COMPARISON_OPS.has(operator)) {
    if (!Array.isArray(operands) || operands.length !== 2) return false;
    return evaluateComparison(
      operator,
      operands as [SDUIExpressionOperand, SDUIExpressionOperand],
      context,
      depth,
    );
  }

  return false;
}

export function evaluateRule(rule: SDUIRule, context: SDUIContext): boolean {
  return evaluate(rule, context, 0);
}

export function evaluateExpression(
  expr: SDUIArithmeticExpression | SDUIExpressionOperand,
  context: SDUIContext,
): number | string | boolean | null {
  if (isPrimitive(expr)) return expr;
  if (isVarOperator(expr)) {
    const resolved = resolveContextPath(context, expr.var);
    if (isPrimitive(resolved)) return resolved;
    return null;
  }
  if (isArithmeticExpression(expr)) {
    return computeArithmetic(expr, context, 0);
  }
  return evaluate(expr as SDUIRule, context, 0);
}

