import type { SDUIContext, SDUIRule, SDUIArithmeticExpression } from '../models';
import { evaluateRule, evaluateExpression } from './jsonLogic';

const CONTEXT: SDUIContext = {
  form: {
    points: 5000,
    reais: 50,
  },
  balance: {
    points: 25720,
    pointsFormatted: '25.720',
  },
  product: {
    code: 206,
    name: 'Abastecimento',
    active: true,
  },
  user: {
    eligible: true,
    blocked: false,
    tier: 'gold',
  },
  empty: null,
};

describe('evaluateRule', () => {
  describe('var operator', () => {
    it('resolves context values for comparison', () => {
      const rule: SDUIRule = { '>': [{ var: 'form.points' }, 0] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves nested context paths', () => {
      const rule: SDUIRule = {
        '==': [{ var: 'product.name' }, 'Abastecimento'],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves both operands from context', () => {
      const rule: SDUIRule = {
        '<=': [{ var: 'form.points' }, { var: 'balance.points' }],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('resolves missing path to empty string', () => {
      const rule: SDUIRule = { '==': [{ var: 'nonexistent.path' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('comparison operators', () => {
    it('== with loose equality', () => {
      expect(evaluateRule({ '==': [1, 1] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '==': [1, '1'] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '==': [1, 2] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '==': [null, null] }, CONTEXT)).toBe(true);
    });

    it('!= with loose inequality', () => {
      expect(evaluateRule({ '!=': [1, 2] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '!=': [1, 1] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '!=': [1, '1'] }, CONTEXT)).toBe(false);
    });

    it('> greater than', () => {
      expect(evaluateRule({ '>': [10, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>': [5, 10] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '>': [5, 5] }, CONTEXT)).toBe(false);
    });

    it('< less than', () => {
      expect(evaluateRule({ '<': [5, 10] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<': [10, 5] }, CONTEXT)).toBe(false);
    });

    it('>= greater than or equal', () => {
      expect(evaluateRule({ '>=': [10, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>=': [5, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '>=': [4, 5] }, CONTEXT)).toBe(false);
    });

    it('<= less than or equal', () => {
      expect(evaluateRule({ '<=': [5, 10] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<=': [5, 5] }, CONTEXT)).toBe(true);
      expect(evaluateRule({ '<=': [6, 5] }, CONTEXT)).toBe(false);
    });

    it('with context values', () => {
      expect(
        evaluateRule({ '>': [{ var: 'form.points' }, 1000] }, CONTEXT),
      ).toBe(true);
      expect(
        evaluateRule({ '<': [{ var: 'form.points' }, 1000] }, CONTEXT),
      ).toBe(false);
    });

    it('string comparison', () => {
      expect(
        evaluateRule(
          { '==': [{ var: 'user.tier' }, 'gold'] },
          CONTEXT,
        ),
      ).toBe(true);
      expect(
        evaluateRule(
          { '!=': [{ var: 'user.tier' }, 'silver'] },
          CONTEXT,
        ),
      ).toBe(true);
    });

    it('boolean comparison', () => {
      expect(
        evaluateRule({ '==': [{ var: 'product.active' }, true] }, CONTEXT),
      ).toBe(true);
      expect(
        evaluateRule({ '==': [{ var: 'user.blocked' }, false] }, CONTEXT),
      ).toBe(true);
    });
  });

  describe('logical operators', () => {
    it('and: all true', () => {
      const rule: SDUIRule = {
        and: [
          { '>': [{ var: 'form.points' }, 0] },
          { '<=': [{ var: 'form.points' }, { var: 'balance.points' }] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('and: one false', () => {
      const rule: SDUIRule = {
        and: [
          { '>': [{ var: 'form.points' }, 0] },
          { '>': [{ var: 'form.points' }, 100000] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('and: empty array returns true (vacuous truth)', () => {
      const rule: SDUIRule = { and: [] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('or: at least one true', () => {
      const rule: SDUIRule = {
        or: [
          { '==': [{ var: 'product.code' }, 205] },
          { '==': [{ var: 'product.code' }, 206] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('or: all false', () => {
      const rule: SDUIRule = {
        or: [
          { '==': [{ var: 'product.code' }, 999] },
          { '==': [{ var: 'product.code' }, 888] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('or: empty array returns false', () => {
      const rule: SDUIRule = { or: [] };
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('!: negation (object syntax)', () => {
      expect(
        evaluateRule(
          { '!': { '==': [{ var: 'product.code' }, 999] } },
          CONTEXT,
        ),
      ).toBe(true);
      expect(
        evaluateRule(
          { '!': { '==': [{ var: 'product.code' }, 206] } },
          CONTEXT,
        ),
      ).toBe(false);
    });

    it('!: negation (array syntax)', () => {
      expect(
        evaluateRule(
          { '!': [{ '==': [1, 1] }] } as unknown as SDUIRule,
          CONTEXT,
        ),
      ).toBe(false);
      expect(
        evaluateRule(
          { '!': [{ '==': [1, 2] }] } as unknown as SDUIRule,
          CONTEXT,
        ),
      ).toBe(true);
    });
  });

  describe('nested logic', () => {
    it('and inside or', () => {
      const rule: SDUIRule = {
        or: [
          {
            and: [
              { '==': [{ var: 'product.code' }, 206] },
              { '>': [{ var: 'form.points' }, 1000] },
            ],
          },
          { '==': [{ var: 'user.tier' }, 'platinum'] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('not inside and', () => {
      const rule: SDUIRule = {
        and: [
          { '!': { '==': [{ var: 'user.blocked' }, true] } },
          { '==': [{ var: 'user.eligible' }, true] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('deeply nested rules', () => {
      const rule: SDUIRule = {
        and: [
          {
            or: [
              { '==': [{ var: 'product.code' }, 205] },
              { '==': [{ var: 'product.code' }, 206] },
            ],
          },
          { '!': { '==': [{ var: 'user.blocked' }, true] } },
          { '>': [{ var: 'balance.points' }, 0] },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('nested rule as comparison operand', () => {
      const rule: SDUIRule = {
        '==': [
          { '>': [{ var: 'form.points' }, 0] } as unknown as SDUIRule,
          true,
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('edge cases & error handling', () => {
    it('returns false for null rule', () => {
      expect(evaluateRule(null as unknown as SDUIRule, CONTEXT)).toBe(false);
    });

    it('returns false for undefined rule', () => {
      expect(evaluateRule(undefined as unknown as SDUIRule, CONTEXT)).toBe(
        false,
      );
    });

    it('returns false for empty object', () => {
      expect(evaluateRule({} as SDUIRule, CONTEXT)).toBe(false);
    });

    it('returns false for unknown operator', () => {
      const rule = { xor: [true, false] } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for comparison with wrong operand count', () => {
      const rule = { '>': [1] } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for comparison with non-array operands', () => {
      const rule = { '>': 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for and with non-array operands', () => {
      const rule = { and: 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('returns false for or with non-array operands', () => {
      const rule = { or: 'invalid' } as unknown as SDUIRule;
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('handles empty context', () => {
      const rule: SDUIRule = { '==': [{ var: 'anything' }, ''] };
      expect(evaluateRule(rule, {})).toBe(true);
    });

    it('handles context value resolving to object (non-primitive)', () => {
      const rule: SDUIRule = { '==': [{ var: 'product' }, null] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('returns false for ordering comparison with non-numeric types', () => {
      expect(evaluateRule({ '>': ['z', 'a'] }, CONTEXT)).toBe(false);
      expect(evaluateRule({ '<': [null, 5] }, CONTEXT)).toBe(false);
      expect(
        evaluateRule(
          { '>=': [{ var: 'product.name' }, 100] },
          CONTEXT,
        ),
      ).toBe(false);
    });

    it('returns false for deeply nested rules exceeding max depth', () => {
      let rule: SDUIRule = { '==': [1, 1] };
      for (let i = 0; i < 25; i++) {
        rule = { and: [rule] };
      }
      expect(evaluateRule(rule, CONTEXT)).toBe(false);
    });

    it('blocks __proto__ access in var paths', () => {
      const rule: SDUIRule = { '==': [{ var: '__proto__' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('blocks constructor access in var paths', () => {
      const rule: SDUIRule = { '==': [{ var: 'product.constructor' }, ''] };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });

  describe('arithmetic as comparison operands', () => {
    it('compares arithmetic result to literal', () => {
      const rule: SDUIRule = {
        '==': [
          { '*': [{ var: 'form.points' }, 0.01] } as SDUIArithmeticExpression,
          50,
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });

    it('compares two arithmetic results', () => {
      const rule: SDUIRule = {
        '>': [
          { '+': [{ var: 'form.points' }, 100] } as unknown as SDUIRule,
          { var: 'form.points' },
        ],
      };
      expect(evaluateRule(rule, CONTEXT)).toBe(true);
    });
  });
});

describe('evaluateExpression', () => {
  describe('addition (+)', () => {
    it('adds two numbers', () => {
      const expr: SDUIArithmeticExpression = { '+': [10, 20] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(30);
    });

    it('adds multiple numbers (variadic)', () => {
      const expr: SDUIArithmeticExpression = { '+': [1, 2, 3, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(10);
    });

    it('adds context values', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'form.points' }, { var: 'form.reais' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(5050);
    });

    it('coerces numeric strings', () => {
      const expr: SDUIArithmeticExpression = { '+': ['10', 20] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(30);
    });
  });

  describe('subtraction (-)', () => {
    it('subtracts two numbers', () => {
      const expr: SDUIArithmeticExpression = { '-': [100, 30] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(70);
    });

    it('subtracts context values', () => {
      const expr: SDUIArithmeticExpression = { '-': [{ var: 'balance.points' }, { var: 'form.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20720);
    });
  });

  describe('multiplication (*)', () => {
    it('multiplies two numbers', () => {
      const expr: SDUIArithmeticExpression = { '*': [5, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20);
    });

    it('multiplies multiple numbers (variadic)', () => {
      const expr: SDUIArithmeticExpression = { '*': [2, 3, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(24);
    });

    it('points to reais conversion', () => {
      const expr: SDUIArithmeticExpression = { '*': [{ var: 'form.points' }, 0.01] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(50);
    });
  });

  describe('division (/)', () => {
    it('divides two numbers', () => {
      const expr: SDUIArithmeticExpression = { '/': [100, 4] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(25);
    });

    it('returns 0 on division by zero', () => {
      const expr: SDUIArithmeticExpression = { '/': [100, 0] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('divides context values', () => {
      const expr: SDUIArithmeticExpression = { '/': [{ var: 'form.reais' }, 0.01] };
      expect(evaluateExpression(expr, CONTEXT)).toBeCloseTo(5000);
    });
  });

  describe('min / max', () => {
    it('returns minimum', () => {
      const expr: SDUIArithmeticExpression = { min: [10, 5, 20, 3] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(3);
    });

    it('returns maximum', () => {
      const expr: SDUIArithmeticExpression = { max: [10, 5, 20, 3] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(20);
    });

    it('min with context values', () => {
      const expr: SDUIArithmeticExpression = { min: [{ var: 'form.points' }, { var: 'balance.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(5000);
    });

    it('max with context values', () => {
      const expr: SDUIArithmeticExpression = { max: [{ var: 'form.points' }, { var: 'balance.points' }] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(25720);
    });
  });

  describe('nested arithmetic', () => {
    it('nested multiplication inside addition', () => {
      // (points * 0.01) + 10
      const expr: SDUIArithmeticExpression = {
        '+': [
          { '*': [{ var: 'form.points' }, 0.01] },
          10,
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBe(60);
    });

    it('complex formula: (balance - points) * factor', () => {
      const expr: SDUIArithmeticExpression = {
        '*': [
          { '-': [{ var: 'balance.points' }, { var: 'form.points' }] },
          0.01,
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBeCloseTo(207.20);
    });

    it('min of computed values', () => {
      const expr: SDUIArithmeticExpression = {
        min: [
          { '*': [{ var: 'form.points' }, 2] },
          { var: 'balance.points' },
        ],
      };
      expect(evaluateExpression(expr, CONTEXT)).toBe(10000);
    });
  });

  describe('passthrough for primitives and var', () => {
    it('returns primitive directly', () => {
      expect(evaluateExpression(42 as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(42);
      expect(evaluateExpression('hello' as unknown as SDUIArithmeticExpression, CONTEXT)).toBe('hello');
      expect(evaluateExpression(true as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(true);
      expect(evaluateExpression(null as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(null);
    });

    it('resolves var operator', () => {
      expect(evaluateExpression({ var: 'form.points' } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(5000);
    });

    it('evaluates boolean rule', () => {
      expect(evaluateExpression({ '>': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(true);
      expect(evaluateExpression({ '<': [10, 5] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(false);
    });
  });

  describe('edge cases', () => {
    it('returns 0 for empty operands array', () => {
      expect(evaluateExpression({ '+': [] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 for non-array operands', () => {
      expect(evaluateExpression({ '+': 'invalid' } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 when operand resolves to non-numeric', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'product.name' }, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('returns 0 for null operand in arithmetic', () => {
      const expr: SDUIArithmeticExpression = { '+': [null, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('returns 0 for subtraction with wrong operand count', () => {
      expect(evaluateExpression({ '-': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
      expect(evaluateExpression({ '-': [1, 2, 3] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('returns 0 for division with wrong operand count', () => {
      expect(evaluateExpression({ '/': [1] } as unknown as SDUIArithmeticExpression, CONTEXT)).toBe(0);
    });

    it('respects max depth', () => {
      // Build deeply nested: +(+(+(... 1, 1), 1), 1) — 25 levels deep
      // At depth > 20, computeArithmetic returns 0
      // Inner levels that exceed depth return 0, so the deepest operand
      // resolves to 0 instead of its true value, capping computation
      let expr: SDUIArithmeticExpression = { '+': [1000, 1000] };
      for (let i = 0; i < 25; i++) {
        expr = { '+': [expr as unknown as number, 1000] };
      }
      // Without depth limit: 2000 + 25*1000 = 27000
      // With depth limit at 20: innermost levels return 0, so result < 27000
      const result = evaluateExpression(expr, CONTEXT) as number;
      expect(result).toBeLessThan(27000);
    });

    it('returns 0 for object resolving to non-primitive via var', () => {
      const expr: SDUIArithmeticExpression = { '+': [{ var: 'product' }, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });

    it('handles boolean operand as non-numeric', () => {
      const expr: SDUIArithmeticExpression = { '+': [true as unknown as number, 10] };
      expect(evaluateExpression(expr, CONTEXT)).toBe(0);
    });
  });
});
